import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../secretFile.txt";

        // Validate and sanitize user input to prevent directory traversal
        if (!userInput.contains("..") && !userInput.contains("/")) {
            try {
                String filePath = "/path/to/directory/" + userInput;
                File file = new File(filePath);

                if (file.exists()) {
                    byte[] fileContent = Files.readAllBytes(Paths.get(filePath));
                    String content = new String(fileContent);
                    System.out.println("File content: " + content);
                } else {
                    System.out.println("File not found.");
                }
            } catch (IOException e) {
                e.printStackTrace();
            }
        } else {
            System.out.println("Invalid input detected. Access denied.");
        }
    }
}

